=<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Attendance Dashboard</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: Arial, sans-serif; background: #f0f2f5; padding: 24px; }
  h1 { color: #1a1a2e; margin-bottom: 8px; font-size: 22px; }
  .cards { display: flex; gap: 16px; margin-bottom: 32px; flex-wrap: wrap; margin-top: 20px; }
  .card { background: white; border-radius: 12px; padding: 20px 28px; flex: 1; min-width: 140px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
  .card h3 { font-size: 12px; color: #888; margin-bottom: 8px; text-transform: uppercase; }
  .card .number { font-size: 36px; font-weight: bold; }
  .late { color: #e74c3c; }
  .ontime { color: #2ecc71; }
  .atrisk { color: #f39c12; }
  .critical { color: #e74c3c; }
  table { width: 100%; background: white; border-radius: 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); border-collapse: collapse; }
  th { background: #1a1a2e; color: white; padding: 14px 16px; text-align: left; font-size: 13px; }
  td { padding: 12px 16px; border-bottom: 1px solid #f0f2f5; font-size: 14px; }
  tr:last-child td { border-bottom: none; }
  tr:hover td { background: #f9f9f9; }
  .badge { padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; }
  .safe { background: #d4edda; color: #155724; }
  .at-risk { background: #fff3cd; color: #856404; }
  .critical-badge { background: #f8d7da; color: #721c24; }
  .excused-badge { background: #cce5ff; color: #004085; }
  .btn-excused { border: none; background: #3498db; color: white; padding: 5px 12px; border-radius: 6px; cursor: pointer; font-size: 12px; }
  .btn-excused:hover { background: #2980b9; }
  .refresh { font-size: 12px; color: #888; margin-bottom: 20px; }
  h2 { margin-bottom: 16px; color: #1a1a2e; font-size: 18px; }
  .sort-bar { margin-bottom: 16px; display: flex; align-items: center; gap: 12px; }
  .sort-bar label { font-size: 14px; color: #555; }
  .sort-bar select { padding: 8px 12px; border-radius: 8px; border: 1px solid #ddd; font-size: 14px; background: white; cursor: pointer; }
</style>
</head>
<body>

<h1>HR Attendance Dashboard — Growify Digital LLP</h1>
<p class="refresh" id="refreshTimer">Auto-refreshing every 60 seconds</p>

<div class="cards">
  <div class="card"><h3>Total Employees</h3><div class="number" id="totalCount">—</div></div>
  <div class="card"><h3>Late This Month</h3><div class="number late" id="lateCount">—</div></div>
  <div class="card"><h3>On Time</h3><div class="number ontime" id="onTimeCount">—</div></div>
  <div class="card"><h3>At Risk (2)</h3><div class="number atrisk" id="atRiskCount">—</div></div>
  <div class="card"><h3>Critical (3+)</h3><div class="number critical" id="criticalCount">—</div></div>
</div>

<h2>All Late Employees</h2>
<div class="sort-bar">
  <label>Sort by:</label>
  <select id="sortSelect" onchange="render()">
    <option value="count-desc">Late Days (High to Low)</option>
    <option value="count-asc">Late Days (Low to High)</option>
    <option value="name-asc">Name (A to Z)</option>
    <option value="name-desc">Name (Z to A)</option>
    <option value="date-desc">Last Warning (Newest)</option>
    <option value="date-asc">Last Warning (Oldest)</option>
  </select>
</div>

<table>
  <thead>
    <tr>
      <th>#</th>
      <th>Employee ID</th>
      <th>Name</th>
      <th>Late Days</th>
      <th>Last Warning</th>
      <th>Status</th>
      <th>Action</th>
    </tr>
  </thead>
  <tbody id="employeeTable"></tbody>
</table>

<script>
const rawData = {{ JSON.stringify($input.all()) }};
let excusedSet = new Set();

function getBadge(id, count) {
  if (excusedSet.has(id)) return '<span class="badge excused-badge">Excused</span>';
  if (count >= 3) return '<span class="badge critical-badge">Critical</span>';
  if (count == 2) return '<span class="badge at-risk">At Risk</span>';
  return '<span class="badge safe">Safe</span>';
}

function render() {
  const rows = rawData.map(r => r.json || r);
  rows.forEach(r => {
  if (r['Excused'] === 'YES') {
    excusedSet.add(r['Employee ID'] || '');
  }
});

  const total = rows.length;
  const lateTotal = rows.filter(r => parseInt(r['Monthly Late Count'] || 0) > 0).length;
  const onTime = total - lateTotal;
  const atRisk = rows.filter(r => parseInt(r['Monthly Late Count'] || 0) == 2).length;
  const critical = rows.filter(r => parseInt(r['Monthly Late Count'] || 0) >= 3).length;

  document.getElementById('totalCount').textContent = total;
  document.getElementById('lateCount').textContent = lateTotal;
  document.getElementById('onTimeCount').textContent = onTime;
  document.getElementById('atRiskCount').textContent = atRisk;
  document.getElementById('criticalCount').textContent = critical;

  const sortVal = document.getElementById('sortSelect')?.value || 'count-desc';

  const filtered = rows
    .filter(r => parseInt(r['Monthly Late Count'] || 0) >= 1)
    .sort((a, b) => {
      const ca = parseInt(a['Monthly Late Count'] || 0);
      const cb = parseInt(b['Monthly Late Count'] || 0);
      const na = (a['Name'] || '').toLowerCase();
      const nb = (b['Name'] || '').toLowerCase();
      const da = a['Last Warning Date'] || '';
      const db = b['Last Warning Date'] || '';
      if (sortVal === 'count-desc') return cb - ca;
      if (sortVal === 'count-asc') return ca - cb;
      if (sortVal === 'name-asc') return na.localeCompare(nb);
      if (sortVal === 'name-desc') return nb.localeCompare(na);
      if (sortVal === 'date-desc') return db.localeCompare(da);
      if (sortVal === 'date-asc') return da.localeCompare(db);
      return 0;
    });

  const tbody = document.getElementById('employeeTable');
  if (filtered.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:#888">No employees at risk</td></tr>';
    return;
  }

  tbody.innerHTML = filtered.map((r, i) => {
    const id = r['Employee ID'] || '';
    const name = r['Name'] || '';
    const count = parseInt(r['Monthly Late Count'] || 0);
    const lastDate = r['Last Warning Date'] || '';
    const isExcused = excusedSet.has(id);
    return `<tr>
      <td>${i + 1}</td>
      <td>${id}</td>
      <td>${name}</td>
      <td>${count}</td>
      <td>${lastDate}</td>
      <td>${getBadge(id, count)}</td>
      <td>${!isExcused ? `<button class="btn-excused" onclick="excuse('${id}')">Mark Excused</button>` : '—'}</td>
    </tr>`;
  }).join('');
}

async function excuse(id) {
  try {
    await fetch('http://localhost:5678/webhook/excuse-employee', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ employeeId: id })
    });
    excusedSet.add(id);
    render();
  } catch(e) {
    alert('Failed to mark as excused. Please try again.');
  }
}

let seconds = 60;
setInterval(() => {
  seconds--;
  document.getElementById('refreshTimer').textContent = `Auto-refreshing in ${seconds} seconds`;
  if (seconds <= 0) { seconds = 60; }
}, 1000);

render();
</script>
</body>
</html>
